-- Light TMS - Catálogos RNDC (empaque, carrocería, producto, errores).
-- Generado desde sql/catalogo_*.csv. Importar en phpMyAdmin tras schema.sql.
SET NAMES utf8mb4;
DROP TABLE IF EXISTS empaque;
CREATE TABLE empaque (codigo VARCHAR(6) PRIMARY KEY, descripcion VARCHAR(200) NOT NULL, peligrosa VARCHAR(3) NULL, tipo_operacion VARCHAR(2) NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
DROP TABLE IF EXISTS carroceria;
CREATE TABLE carroceria (id INT AUTO_INCREMENT PRIMARY KEY, codigo VARCHAR(6) NOT NULL, descripcion VARCHAR(150) NOT NULL, KEY idx_carr_cod (codigo)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
DROP TABLE IF EXISTS producto;
CREATE TABLE producto (id INT AUTO_INCREMENT PRIMARY KEY, codigo VARCHAR(10) NOT NULL, nombre VARCHAR(400) NOT NULL, capitulo VARCHAR(200) NULL, peligrosa VARCHAR(3) NULL, aplica_sicetac VARCHAR(3) NULL, KEY idx_prod_cod (codigo), KEY idx_prod_nom (nombre(60))) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
DROP TABLE IF EXISTS error_rndc;
CREATE TABLE error_rndc (id INT AUTO_INCREMENT PRIMARY KEY, proceso_id VARCHAR(6) NULL, codigo VARCHAR(15) NOT NULL, mensaje VARCHAR(600) NULL, variable VARCHAR(60) NULL, tipo VARCHAR(3) NULL, proceso VARCHAR(120) NULL, solucion VARCHAR(600) NULL, KEY idx_err_cod (codigo)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
